      setSummary(s.data);
      setChartData(c.data.chart_data.map(d => ({
        ...d,
        date: new Date(d.date).toLocaleDateString('en', { month: 'short', day: 'numeric' }),
      })));
    }).catch(() => toast.error('Failed to load analytics'))
