              <Tooltip content={<CustomTooltip />} />
              <Bar dataKey="messages_received" name="Messages" fill="#a855f7" radius={[6,6,0,0]} />
              <Bar dataKey="link_clicks" name="Clicks" fill="#ec4899" radius={[6,6,0,0]} />
